- "individuals" refers to "users" in the context of the SQL query;
- "typical number of times" corresponds to the average value of access attempts;
- "access was marked" refers to the `access_status` in the SQL query.

sql:
SELECT manufacturer_id, manufacturer_name
FROM manufacturers
WHERE manufacturer_id NOT IN (SELECT manufacturer FROM devices);

SELECT count(*) 
FROM device_access 
WHERE device_id = 1;

SELECT ip_address
FROM devices
WHERE device_id = 1;

SELECT d.device_id, d.device_name, dt.data_rate
FROM devices d
JOIN device_types dt ON d.device_type = dt.device_type_id
WHERE dt.data_rate = (
  SELECT MAX(data_rate) FROM device_types
);

SELECT device_name, firmware_version, last_update_date 
FROM devices 
WHERE firmware_version != (SELECT MAX(firmware_version) FROM devices);

SELECT devices.device_name, device_types.device_type_name
FROM devices
JOIN device_types ON devices.device_type = device_types.device_type_id;
